/**
 * 认证中间件
 */

const authUtils = require('../utils/auth');
const logger = require('../config/logger');

/**
 * JWT令牌认证中间件
 */
function authenticateToken(req, res, next) {
  const authHeader = req.headers.authorization;
  const token = extractTokenFromHeader(authHeader);

  if (!token) {
    return res.status(401).json({
      error: '未提供访问令牌'
    });
  }

  try {
    const decoded = authUtils.verifyToken(token);
    req.user = decoded;
    next();
  } catch (error) {
    if (error.message === 'Token已过期') {
      return res.status(401).json({
        error: '访问令牌已过期'
      });
    } else {
      return res.status(403).json({
        error: '无效的访问令牌'
      });
    }
  }
}

/**
 * 角色验证中间件生成器
 */
function requireRole(roles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({
        error: '需要身份验证'
      });
    }

    const userRole = req.user.role;
    const allowedRoles = Array.isArray(roles) ? roles : [roles];

    if (allowedRoles.includes(userRole)) {
      next();
    } else {
      return res.status(403).json({
        error: '权限不足'
      });
    }
  };
}

/**
 * 可选认证中间件（不强制要求认证）
 */
function optionalAuth(req, res, next) {
  const authHeader = req.headers.authorization;
  const token = extractTokenFromHeader(authHeader);

  if (token) {
    try {
      const decoded = authUtils.verifyToken(token);
      req.user = decoded;
    } catch (error) {
      // 可选认证失败时不阻止请求，只是不设置用户信息
      req.user = null;
    }
  } else {
    req.user = null;
  }

  next();
}

/**
 * 资源所有权验证中间件
 */
function requireOwnership(req, res, next) {
  if (!req.user) {
    return res.status(401).json({
      error: '需要身份验证'
    });
  }

  // 管理员可以访问任何资源
  if (req.user.role === 'admin') {
    return next();
  }

  // 检查用户是否是资源所有者
  const userId = req.user.id;
  const resourceUserId = req.params.userId || req.body.userId || req.query.userId;

  if (userId.toString() === resourceUserId.toString()) {
    next();
  } else {
    return res.status(403).json({
      error: '只能访问自己的资源'
    });
  }
}

/**
 * 从Authorization头中提取Bearer令牌
 */
function extractTokenFromHeader(authHeader) {
  if (!authHeader) {
    return null;
  }

  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return null;
  }

  return parts[1];
}

module.exports = {
  authenticateToken,
  requireRole,
  optionalAuth,
  requireOwnership,
  extractTokenFromHeader
};

/**
 * 缓存中间件
 * 为Express路由提供自动缓存功能
 */

const { cacheIntegration } = require('../utils/cache/CacheIntegration');
const logger = require('../config/logger');

/**
 * 创建缓存中间件
 * @param {Object} options - 缓存选项
 * @param {number} options.ttl - 缓存时间（秒）
 * @param {string|function} options.keyGenerator - 缓存键生成器
 * @param {function} options.condition - 缓存条件判断函数
 * @param {boolean} options.skipOnError - 错误时是否跳过缓存
 */
function createCacheMiddleware(options = {}) {
  const {
    ttl = 300,
    keyGenerator = defaultKeyGenerator,
    condition = () => true,
    skipOnError = true
  } = options;

  return async (req, res, next) => {
    try {
      // 检查是否满足缓存条件
      if (!condition(req)) {
        return next();
      }

      // 生成缓存键
      const cacheKey = typeof keyGenerator === 'function' 
        ? keyGenerator(req) 
        : keyGenerator;

      // 尝试从缓存获取数据
      const cachedData = await cacheIntegration.cacheManager.get(cacheKey);

      if (cachedData !== undefined) {
        logger.debug('缓存命中', { key: cacheKey, path: req.path });

        // 设置缓存头
        res.set('X-Cache', 'HIT');
        res.set('X-Cache-Key', cacheKey);

        return res.json(cachedData);
      }

      // 缓存未命中，继续执行
      logger.debug('缓存未命中', { key: cacheKey, path: req.path });
      res.set('X-Cache', 'MISS');
      res.set('X-Cache-Key', cacheKey);

      // 拦截响应以缓存数据
      const originalJson = res.json;
      res.json = function(data) {
        // 只缓存成功的响应
        if (res.statusCode >= 200 && res.statusCode < 300) {
          cacheIntegration.cacheManager.set(cacheKey, data, ttl)
            .then(() => {
              logger.debug('数据已缓存', { key: cacheKey, ttl });
            })
            .catch(error => {
              logger.error('缓存设置失败', { key: cacheKey, error: error.message });
            });
        }

        return originalJson.call(this, data);
      };

      next();
    } catch (error) {
      logger.error('缓存中间件错误', { error: error.message, path: req.path });

      if (skipOnError) {
        next();
      } else {
        next(error);
      }
    }
  };
}

/**
 * 默认缓存键生成器
 */
function defaultKeyGenerator(req) {
  const method = req.method;
  const path = req.path;
  const query = JSON.stringify(req.query);
  const userId = req.user ? req.user.id : 'anonymous';

  return `route:${method}:${path}:${userId}:${Buffer.from(query).toString('base64')}`;
}

/**
 * 用户相关数据缓存中间件
 */
function userCacheMiddleware(ttl = 1800) {
  return createCacheMiddleware({
    ttl,
    keyGenerator: (req) => {
      const userId = req.user ? req.user.id : req.params.userId || req.params.id;
      return `user:${userId}:${req.path}`;
    },
    condition: (req) => req.method === 'GET' && (req.user || req.params.userId)
  });
}

/**
 * 订单相关数据缓存中间件
 */
function orderCacheMiddleware(ttl = 600) {
  return createCacheMiddleware({
    ttl,
    keyGenerator: (req) => {
      const orderId = req.params.orderId || req.params.id;
      const userId = req.user ? req.user.id : 'anonymous';
      return `order:${orderId}:${userId}:${req.path}`;
    },
    condition: (req) => req.method === 'GET' && req.params.orderId
  });
}

/**
 * 供应商相关数据缓存中间件
 */
function providerCacheMiddleware(ttl = 3600) {
  return createCacheMiddleware({
    ttl,
    keyGenerator: (req) => {
      const providerId = req.params.providerId || req.params.id;
      return `provider:${providerId}:${req.path}`;
    },
    condition: (req) => req.method === 'GET'
  });
}

/**
 * 报价相关数据缓存中间件
 */
function quoteCacheMiddleware(ttl = 300) {
  return createCacheMiddleware({
    ttl,
    keyGenerator: (req) => {
      const quoteParams = {
        from: req.body.from || req.query.from,
        to: req.body.to || req.query.to,
        weight: req.body.weight || req.query.weight,
        type: req.body.type || req.query.type
      };
      const paramsHash = Buffer.from(JSON.stringify(quoteParams)).toString('base64');
      return `quote:${paramsHash}`;
    },
    condition: (req) => req.path.includes('/quote')
  });
}

/**
 * 统计数据缓存中间件
 */
function statsCacheMiddleware(ttl = 900) {
  return createCacheMiddleware({
    ttl,
    keyGenerator: (req) => {
      const timeRange = req.query.timeRange || 'day';
      const userId = req.user ? req.user.id : 'all';
      return `stats:${timeRange}:${userId}:${req.path}`;
    },
    condition: (req) => req.method === 'GET' && req.path.includes('/stats')
  });
}

/**
 * 缓存失效中间件
 * 在数据更新时自动清除相关缓存
 */
function cacheInvalidationMiddleware(patterns = []) {
  return async (req, res, next) => {
    // 只在非GET请求时执行缓存失效
    if (req.method === 'GET') {
      return next();
    }

    const originalJson = res.json;
    res.json = async function(data) {
      // 只在成功响应时清除缓存
      if (res.statusCode >= 200 && res.statusCode < 300) {
        try {
          // 根据路径模式清除相关缓存
          for (const pattern of patterns) {
            if (typeof pattern === 'function') {
              await pattern(req, res);
            } else if (typeof pattern === 'string') {
              // 简单的模式匹配缓存清除
              if (req.path.includes(pattern)) {
                logger.debug('清除缓存模式', { pattern, path: req.path });
                // 这里可以实现更复杂的缓存清除逻辑
              }
            }
          }
        } catch (error) {
          logger.error('缓存失效失败', { error: error.message });
        }
      }

      return originalJson.call(this, data);
    };

    next();
  };
}

/**
 * 缓存统计中间件
 * 收集缓存使用统计信息
 */
function cacheStatsMiddleware() {
  return (req, res, next) => {
    const startTime = Date.now();

    const originalJson = res.json;
    res.json = function(data) {
      const duration = Date.now() - startTime;
      const cacheStatus = res.get('X-Cache') || 'BYPASS';

      // 记录缓存统计
      logger.debug('请求缓存统计', {
        path: req.path,
        method: req.method,
        cacheStatus,
        duration,
        statusCode: res.statusCode
      });

      return originalJson.call(this, data);
    };

    next();
  };
}

module.exports = {
  createCacheMiddleware,
  userCacheMiddleware,
  orderCacheMiddleware,
  providerCacheMiddleware,
  quoteCacheMiddleware,
  statsCacheMiddleware,
  cacheInvalidationMiddleware,
  cacheStatsMiddleware
};

/**
 * 全局错误处理中间件
 *
 * 提供统一的错误处理机制，包括异步路由错误包装器、
 * 全局错误处理中间件和未捕获异常处理
 */

const logger = require('../config/logger');
const config = require('../config/env');

/**
 * 异步路由错误处理包装器
 * 自动捕获async函数中的未处理异常并传递给错误处理中间件
 *
 * @param {Function} fn - 异步路由处理函数
 * @returns {Function} - 包装后的路由处理函数
 */
function asyncHandler(fn) {
  return (req, res, next) => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

/**
 * 全局错误处理中间件
 * 处理所有未被路由捕获的错误
 *
 * @param {Error} err - 错误对象
 * @param {Object} req - Express请求对象
 * @param {Object} res - Express响应对象
 * @param {Function} next - Express next函数
 */
function globalErrorHandler(err, req, res, next) {
  // 记录详细的错误信息
  logger.error('未捕获的错误:', {
    message: err.message,
    stack: err.stack,
    url: req.originalUrl,
    method: req.method,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    userId: req.user?.id,
    timestamp: new Date().toISOString(),
    errorType: err.constructor.name,
  });

  // 确定错误状态码
  let statusCode = err.status || err.statusCode || 500;

  // 处理特定类型的错误
  if (err.name === 'ValidationError') {
    statusCode = 400;
  } else if (err.name === 'UnauthorizedError' || err.message.includes('unauthorized')) {
    statusCode = 401;
  } else if (err.name === 'ForbiddenError' || err.message.includes('forbidden')) {
    statusCode = 403;
  } else if (err.name === 'NotFoundError' || err.message.includes('not found')) {
    statusCode = 404;
  }

  // 构建错误响应
  const isDevelopment = !config.isProduction();
  const errorResponse = {
    error: isDevelopment ? err.message : getProductionErrorMessage(statusCode),
    timestamp: new Date().toISOString(),
    path: req.originalUrl,
    method: req.method,
  };

  // 在开发环境中包含更多调试信息
  if (isDevelopment) {
    errorResponse.stack = err.stack;
    errorResponse.details = err.details || null;
  }

  // 发送错误响应
  res.status(statusCode).json(errorResponse);
}

/**
 * 获取生产环境友好的错误消息
 *
 * @param {number} statusCode - HTTP状态码
 * @returns {string} - 用户友好的错误消息
 */
function getProductionErrorMessage(statusCode) {
  switch (statusCode) {
    case 400:
      return '请求参数错误';
    case 401:
      return '身份验证失败，请重新登录';
    case 403:
      return '权限不足，无法访问此资源';
    case 404:
      return '请求的资源不存在';
    case 429:
      return '请求过于频繁，请稍后重试';
    case 500:
    default:
      return '服务器内部错误，请稍后重试';
  }
}

/**
 * 404错误处理中间件
 * 处理未匹配到任何路由的请求
 */
function notFoundHandler(req, res, next) {
  const error = new Error(`路由 ${req.originalUrl} 不存在`);
  error.status = 404;
  next(error);
}

/**
 * 初始化全局错误处理
 * 设置未捕获异常和Promise拒绝的处理器
 */
function initializeErrorHandling() {
  // 处理未捕获的Promise拒绝
  process.on('unhandledRejection', (reason, promise) => {
    logger.error('未处理的Promise拒绝:', {
      reason: reason,
      promise: promise,
      stack: reason?.stack,
      timestamp: new Date().toISOString(),
    });

    // 在生产环境中，记录错误但不退出进程
    // 在开发环境中，可以选择退出进程以便调试
    if (!config.isProduction()) {
      console.error('未处理的Promise拒绝，进程将在5秒后退出...');
      setTimeout(() => {
        process.exit(1);
      }, 5000);
    }
  });

  // 处理未捕获的异常
  process.on('uncaughtException', error => {
    logger.error('未捕获的异常:', {
      message: error.message,
      stack: error.stack,
      timestamp: new Date().toISOString(),
    });

    // 未捕获的异常通常表示严重问题，应该退出进程
    console.error('未捕获的异常，进程将退出...');
    process.exit(1);
  });

  // 处理进程退出信号
  process.on('SIGTERM', () => {
    logger.info('收到SIGTERM信号，正在优雅关闭...');
    // 这里可以添加清理逻辑
    process.exit(0);
  });

  process.on('SIGINT', () => {
    logger.info('收到SIGINT信号，正在优雅关闭...');
    // 这里可以添加清理逻辑
    process.exit(0);
  });
}

/**
 * 创建带有重试机制的异步处理器
 *
 * @param {Function} fn - 异步函数
 * @param {number} maxRetries - 最大重试次数
 * @param {number} retryDelay - 重试延迟（毫秒）
 * @returns {Function} - 包装后的函数
 */
function asyncHandlerWithRetry(fn, maxRetries = 3, retryDelay = 1000) {
  return asyncHandler(async (req, res, next) => {
    let lastError;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await fn(req, res, next);
      } catch (error) {
        lastError = error;

        // 如果是客户端错误（4xx），不重试
        if (error.status && error.status >= 400 && error.status < 500) {
          throw error;
        }

        // 如果不是最后一次尝试，等待后重试
        if (attempt < maxRetries) {
          logger.warn(`操作失败，第${attempt}次重试...`, {
            error: error.message,
            url: req.originalUrl,
            attempt: attempt,
            maxRetries: maxRetries,
          });

          await new Promise(resolve => setTimeout(resolve, retryDelay * attempt));
        }
      }
    }

    // 所有重试都失败，抛出最后一个错误
    throw lastError;
  });
}

module.exports = {
  asyncHandler,
  asyncHandlerWithRetry,
  globalErrorHandler,
  notFoundHandler,
  initializeErrorHandling,
};

