                db.run('ROLLBACK');
                return res.status(500).json({ error: '删除订单失败' });
              }

              if (this.changes === 0) {
                db.run('ROLLBACK');
                return res.status(404).json({ error: '订单不存在或无权限操作' });
              }

              // 提交事务
              db.run('COMMIT', commitErr => {
                if (commitErr) {
                  console.error('提交事务失败:', commitErr);
                  return res.status(500).json({ error: '删除订单失败' });
