// 管理员创建用户
router.post(
  '/create',
  authenticateToken,
  requireRole(ROLES.ADMIN),
  registerValidation,
  async (req, res) => {
    const validationError = handleValidationErrors(req, res);
    if (validationError) {
      return;
    }

    const { email, password, name } = req.body;
    const userId = uuidv4();
    const createdAt = new Date().toISOString();

    try {
      // 检查邮箱是否已存在
      db.get('SELECT id FROM users WHERE email = ?', [email], async (err, existingUser) => {
        if (err) {
          logger.error('检查用户邮箱失败', { error: err.message });
          return res.status(500).json({ error: '创建用户失败' });
        }

        if (existingUser) {
          return res.status(400).json({ error: '邮箱已被使用' });
        }

        // 检查用户名是否已存在（用户名现在是必填项）
        db.get('SELECT id FROM users WHERE name = ?', [name], async (err, existingUserByName) => {
          if (err) {
            logger.error('检查用户名失败', { error: err.message });
            return res.status(500).json({ error: '创建用户失败' });
          }

          if (existingUserByName) {
            return res.status(400).json({ error: '用户名已被使用' });
          }

          // 创建用户
          await createUserRecord();
        });

        async function createUserRecord() {
          try {
            // 加密密码
            const hashedPassword = await bcrypt.hash(password, 10);

            // 插入用户记录
            db.run(
              'INSERT INTO users (id, email, password, name, role, createdAt, isActive) VALUES (?, ?, ?, ?, ?, ?, ?)',
              [userId, email, hashedPassword, name, ROLES.USER, createdAt, 1],
              function (err) {
                if (err) {
                  logger.error('创建用户失败', { error: err.message, email, name });
                  return res.status(500).json({ error: '创建用户失败' });
                }

                logger.info('管理员创建用户成功', {
                  userId,
                  email,
                  name,
                  adminId: req.user.id,
                  ip: req.ip,
                });

                res.status(201).json({
                  message: '用户创建成功',
                  user: {
                    id: userId,
                    email,
                    name,
                    role: ROLES.USER,
                    createdAt,
                    isActive: 1,
                  },
                });
              }
            );
          } catch (error) {
            logger.error('密码加密失败', { error: error.message });
            res.status(500).json({ error: '创建用户失败' });
          }
        }
      });
    } catch (error) {
      logger.error('创建用户处理失败', { error: error.message, stack: error.stack });
      res.status(500).json({ error: '创建用户失败，请稍后重试' });
    }
  }
);

// 用户登录（邮箱密码方式）
router.post(
  '/login',
  [body('email').isEmail().normalizeEmail(), body('password').notEmpty().trim()],
  async (req, res) => {
    const validationError = handleValidationErrors(req, res);
    if (validationError) {
      return;
    }

    const { email, password } = req.body;

    try {
      db.get('SELECT * FROM users WHERE email = ? AND isActive = 1', [email], async (err, user) => {
        if (err) {
          logger.error('用户登录查询失败', { error: err.message });
          return res.status(500).json({ error: '服务器错误' });
        }

        if (!user) {
          logger.warn('用户登录失败：用户不存在或已禁用', { email, ip: req.ip });
          return res.status(401).json({ error: '邮箱或密码错误' });
        }

        // 验证密码
        const isValidPassword = await bcrypt.compare(password, user.password);
        if (!isValidPassword) {
          logger.warn('用户登录失败：密码错误', { email, ip: req.ip });
          return res.status(401).json({ error: '邮箱或密码错误' });
        }

        // 生成tokens
        const userInfo = {
          id: user.id,
          email: user.email,
          name: user.name,
          role: user.role,
        };

        const accessToken = generateAccessToken(userInfo);
        const refreshToken = generateRefreshToken(userInfo);

        logger.info('用户登录成功', { userId: user.id, email, ip: req.ip });

        res.json({
          accessToken,
          refreshToken,
          user: userInfo,
        });
      });
    } catch (error) {
      logger.error('用户登录处理失败', { error: error.message, stack: error.stack });
      res.status(500).json({ error: '登录失败，请稍后重试' });
    }
  }
);

