  const emoji = type === 'success' ? '✅' : type === 'error' ? '🚨' : 'ℹ️';
  const fullMessage = `${emoji} 【物流报价系统备份】\n\n${message}\n\n时间: ${new Date().toLocaleString('zh-CN')}`;

  try {
