/**
 * P2级单元测试体系建立脚本
 * 
 * 功能：
 * 1. 安装测试框架和工具
 * 2. 配置Jest测试环境
 * 3. 创建测试目录结构
 * 4. 生成核心业务逻辑测试模板
 * 5. 设置测试覆盖率报告
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

class UnitTestSetup {
  constructor() {
    this.projectRoot = path.join(__dirname, '../..');
    this.testDir = path.join(this.projectRoot, 'tests/unit');
    this.startTime = Date.now();
  }

  log(message, type = 'info') {
    const timestamp = new Date().toISOString();
    const prefix = type === 'error' ? '❌' : type === 'warn' ? '⚠️' : type === 'success' ? '✅' : 'ℹ️';
    console.log(`[${timestamp}] ${prefix} ${message}`);
  }

  // 安装测试依赖
  async installTestDependencies() {
    this.log('安装测试框架和工具...');

    const testDependencies = [
      'jest@^29.7.0',
      'supertest@^6.3.0',
      '@jest/globals@^29.7.0',
      'jest-environment-node@^29.7.0',
      'jest-coverage-badges@^1.1.2',
      'sqlite3@^5.1.6'
    ];

    try {
      this.log('正在安装测试依赖...');
      const installCommand = `npm install --save-dev ${testDependencies.join(' ')}`;
      execSync(installCommand, { 
        cwd: this.projectRoot, 
        stdio: 'inherit' 
      });

      this.log('✅ 测试依赖安装完成', 'success');
      return true;
    } catch (error) {
      this.log(`测试依赖安装失败: ${error.message}`, 'error');
      return false;
    }
  }

  // 创建Jest配置
  createJestConfig() {
    this.log('创建Jest配置...');

    const jestConfig = {
      testEnvironment: 'node',
      roots: ['<rootDir>/tests/unit'],
      testMatch: [
        '**/tests/unit/**/*.test.js',
        '**/tests/unit/**/*.spec.js'
      ],
      collectCoverageFrom: [
        'routes/**/*.js',
        'utils/**/*.js',
        'middleware/**/*.js',
        'db/**/*.js',
        '!**/node_modules/**',
        '!**/tests/**',
        '!**/coverage/**'
      ],
      coverageDirectory: 'coverage',
      coverageReporters: [
        'text',
        'lcov',
        'html',
        'json-summary'
      ],
      coverageThreshold: {
        global: {
          branches: 60,
          functions: 60,
          lines: 60,
          statements: 60
        }
      },
      setupFilesAfterEnv: ['<rootDir>/tests/unit/setup.js'],
      testTimeout: 10000,
      verbose: true,
      forceExit: true,
      clearMocks: true,
      resetMocks: true,
      restoreMocks: true
    };

    const configPath = path.join(this.projectRoot, 'jest.config.js');
    const configContent = `module.exports = ${JSON.stringify(jestConfig, null, 2)};`;

    fs.writeFileSync(configPath, configContent);

    this.log('✅ Jest配置创建完成', 'success');
    return true;
  }

  // 创建测试目录结构
  createTestDirectories() {
    this.log('创建测试目录结构...');

    const directories = [
      'tests/unit',
      'tests/unit/routes',
      'tests/unit/utils',
      'tests/unit/middleware',
      'tests/unit/db',
      'tests/unit/fixtures',
      'tests/unit/mocks'
    ];

    directories.forEach(dir => {
      const fullPath = path.join(this.projectRoot, dir);
      if (!fs.existsSync(fullPath)) {
        fs.mkdirSync(fullPath, { recursive: true });
        this.log(`创建目录: ${dir}`);
      }
    });

    this.log('✅ 测试目录结构创建完成', 'success');
    return true;
  }

  // 创建测试设置文件
  createTestSetup() {
    this.log('创建测试设置文件...');

