/**
 * 智能缓存管理器
 * 提供多层缓存、自动过期、性能监控等功能
 */

const NodeCache = require('node-cache');
const LRU = require('lru-cache');
const logger = require('../../config/logger');

class SmartCacheManager {
  constructor(options = {}) {
    // L1缓存：内存缓存（最快）
    this.l1Cache = new NodeCache({
      stdTTL: options.l1TTL || 300, // 5分钟
      checkperiod: options.l1CheckPeriod || 60, // 1分钟检查一次
      useClones: false,
      deleteOnExpire: true,
      maxKeys: options.l1MaxKeys || 1000
    });

    // L2缓存：LRU缓存（中等速度，更大容量）
    this.l2Cache = new LRU({
      max: options.l2MaxItems || 5000,
      ttl: options.l2TTL || 1800000, // 30分钟
      allowStale: false,
      updateAgeOnGet: true,
      updateAgeOnHas: true
    });

    // 缓存统计
    this.stats = {
      l1: { hits: 0, misses: 0, sets: 0, deletes: 0 },
      l2: { hits: 0, misses: 0, sets: 0, deletes: 0 },
      total: { hits: 0, misses: 0, sets: 0, deletes: 0 }
    };

    // 性能监控
    this.performanceMetrics = {
      avgGetTime: 0,
      avgSetTime: 0,
      totalOperations: 0
    };

    this.setupEventListeners();
  }

  setupEventListeners() {
    // L1缓存事件监听
    this.l1Cache.on('set', (key, value) => {
      this.stats.l1.sets++;
      this.stats.total.sets++;
    });

    this.l1Cache.on('del', (key, value) => {
      this.stats.l1.deletes++;
      this.stats.total.deletes++;
    });

    this.l1Cache.on('expired', (key, value) => {
      logger.debug('L1缓存过期', { key });
    });
  }

  /**
   * 获取缓存值
   * @param {string} key - 缓存键
   * @returns {*} 缓存值或undefined
   */
  async get(key) {
    const startTime = Date.now();

    try {
      // 先尝试L1缓存
      let value = this.l1Cache.get(key);
      if (value !== undefined) {
        this.stats.l1.hits++;
        this.stats.total.hits++;
        this.updatePerformanceMetrics('get', startTime);
        return value;
      }

      // 再尝试L2缓存
      value = this.l2Cache.get(key);
      if (value !== undefined) {
        this.stats.l2.hits++;
        this.stats.total.hits++;

        // 将L2缓存的值提升到L1缓存
        this.l1Cache.set(key, value);

        this.updatePerformanceMetrics('get', startTime);
        return value;
      }

      // 缓存未命中
      this.stats.l1.misses++;
      this.stats.l2.misses++;
      this.stats.total.misses++;

      this.updatePerformanceMetrics('get', startTime);
      return undefined;
    } catch (error) {
      logger.error('缓存获取失败', { key, error: error.message });
      return undefined;
    }
  }

  /**
   * 设置缓存值
   * @param {string} key - 缓存键
   * @param {*} value - 缓存值
   * @param {number} ttl - 过期时间（秒）
   */
  async set(key, value, ttl) {
    const startTime = Date.now();

    try {
      // 同时设置L1和L2缓存
      this.l1Cache.set(key, value, ttl);
      this.l2Cache.set(key, value, { ttl: (ttl || 1800) * 1000 });

      this.updatePerformanceMetrics('set', startTime);
      return true;
    } catch (error) {
      logger.error('缓存设置失败', { key, error: error.message });
      return false;
    }
  }

  /**
   * 删除缓存
   * @param {string} key - 缓存键
   */
  async del(key) {
    try {
      this.l1Cache.del(key);
      this.l2Cache.delete(key);
      return true;
    } catch (error) {
      logger.error('缓存删除失败', { key, error: error.message });
      return false;
    }
  }

  /**
   * 清空所有缓存
   */
  async flush() {
    try {
      this.l1Cache.flushAll();
      this.l2Cache.clear();
      logger.info('所有缓存已清空');
      return true;
    } catch (error) {
      logger.error('缓存清空失败', { error: error.message });
      return false;
    }
  }

  /**
   * 获取缓存统计信息
   */
  getStats() {
    const l1Keys = this.l1Cache.keys();
    const l2Size = this.l2Cache.size;

    return {
      ...this.stats,
      l1KeyCount: l1Keys.length,
      l2KeyCount: l2Size,
      hitRate: this.stats.total.hits / (this.stats.total.hits + this.stats.total.misses) || 0,
      performance: this.performanceMetrics
    };
  }

  /**
   * 更新性能指标
   */
  updatePerformanceMetrics(operation, startTime) {
    const duration = Date.now() - startTime;
    this.performanceMetrics.totalOperations++;

    if (operation === 'get') {
      this.performanceMetrics.avgGetTime = 
        (this.performanceMetrics.avgGetTime + duration) / 2;
    } else if (operation === 'set') {
      this.performanceMetrics.avgSetTime = 
        (this.performanceMetrics.avgSetTime + duration) / 2;
    }
  }

  /**
   * 缓存预热
   */
  async warmUp(dataLoader) {
    logger.info('开始缓存预热...');

    try {
      // 预加载常用数据
      const providers = await dataLoader.getActiveProviders();
      await this.set('active_providers', providers, 3600); // 1小时

      const recentOrders = await dataLoader.getRecentOrders(50);
      await this.set('recent_orders', recentOrders, 1800); // 30分钟

      logger.info('缓存预热完成', { 
        providers: providers.length, 
        orders: recentOrders.length 
      });
    } catch (error) {
      logger.error('缓存预热失败', { error: error.message });
    }
  }
}

module.exports = SmartCacheManager;

/**
 * 缓存性能监控器
 */

const logger = require('../../../config/logger');

class CacheMonitor {
  constructor(cacheManager) {
    this.cacheManager = cacheManager;
    this.monitoringInterval = null;
    this.alertThresholds = {
      hitRate: 0.7, // 命中率低于70%时告警
      avgResponseTime: 100, // 平均响应时间超过100ms时告警
      memoryUsage: 0.8 // 内存使用率超过80%时告警
    };
  }

  /**
   * 开始监控
   */
  startMonitoring(intervalMs = 60000) {
    this.monitoringInterval = setInterval(() => {
      this.checkPerformance();
    }, intervalMs);

    logger.info('缓存监控已启动', { interval: intervalMs });
  }

  /**
   * 停止监控
   */
  stopMonitoring() {
    if (this.monitoringInterval) {
      clearInterval(this.monitoringInterval);
      this.monitoringInterval = null;
      logger.info('缓存监控已停止');
    }
  }

  /**
   * 检查缓存性能
   */
  checkPerformance() {
    const stats = this.cacheManager.getStats();

    // 检查命中率
    if (stats.hitRate < this.alertThresholds.hitRate) {
      logger.warn('缓存命中率过低', { 
        hitRate: stats.hitRate,
        threshold: this.alertThresholds.hitRate 
      });
    }

    // 检查响应时间
    if (stats.performance.avgGetTime > this.alertThresholds.avgResponseTime) {
      logger.warn('缓存响应时间过长', { 
        avgGetTime: stats.performance.avgGetTime,
        threshold: this.alertThresholds.avgResponseTime 
      });
    }

    // 记录性能指标
    logger.debug('缓存性能指标', stats);
  }

  /**
   * 生成性能报告
   */
  generateReport() {
    const stats = this.cacheManager.getStats();

    return {
      timestamp: new Date().toISOString(),
      cacheStats: stats,
      recommendations: this.generateRecommendations(stats)
    };
  }

  /**
   * 生成优化建议
   */
  generateRecommendations(stats) {
    const recommendations = [];

    if (stats.hitRate < 0.8) {
      recommendations.push('考虑增加缓存TTL或预热更多数据');
    }

    if (stats.performance.avgGetTime > 50) {
      recommendations.push('考虑优化缓存键结构或减少缓存大小');
    }

    if (stats.l1KeyCount > 800) {
      recommendations.push('L1缓存接近容量上限，考虑增加容量或调整策略');
    }

    return recommendations;
  }
}

module.exports = CacheMonitor;

const Redis = require('ioredis');
const logger = require('../config/logger');
const { SimpleCache } = require('./cache'); // 引入现有的内存缓存

// Redis配置
const redisConfig = {
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD || undefined,
  db: process.env.REDIS_DB || 0,
  keyPrefix: 'wlbj:',
  retryStrategy: times => {
    // 如果重试次数超过3次，就停止重试
    if (times > 3) {
      return null;
    }
    const delay = Math.min(times * 1000, 5000);
    return delay;
  },
  maxRetriesPerRequest: 1,
  enableReadyCheck: false,
  enableOfflineQueue: false,
  connectTimeout: 5000,
  lazyConnect: true,
};

// 创建Redis客户端
let redis = null;
let redisAvailable = false;
let redisConnectionAttempted = false;

// 只有在明确配置了Redis的情况下才尝试连接
const shouldUseRedis = process.env.REDIS_HOST || process.env.REDIS_ENABLED === 'true';

if (shouldUseRedis) {
  try {
    redis = new Redis(redisConfig);
    redisConnectionAttempted = true;

    redis.on('connect', () => {
      logger.info('Redis连接成功');
      redisAvailable = true;
    });

    redis.on('error', err => {
      if (!redisAvailable) {
        logger.warn('Redis服务不可用，将使用内存缓存');
      }
      redisAvailable = false;
    });

    redis.on('close', () => {
      redisAvailable = false;
    });
  } catch (error) {
    logger.warn('Redis初始化失败，将使用内存缓存:', error.message);
    redisAvailable = false;
  }
} else {
  logger.info('未配置Redis，使用内存缓存');
}

// 创建本地内存缓存实例（作为L1缓存）
const memoryCache = new SimpleCache();

/**
 * 多级缓存类
 * L1: 内存缓存（快速，容量小）
 * L2: Redis缓存（较快，容量大，支持分布式）
 */
class MultiLevelCache {
  constructor() {
    this.defaultTTL = 300; // 默认5分钟
    this.l1TTL = 60; // L1缓存默认1分钟
  }

  /**
   * 生成缓存键
   */
  generateKey(namespace, ...parts) {
    return `${namespace}:${parts.join(':')}`;
  }

  /**
   * 从缓存获取数据（先L1后L2）
   */
  async get(key) {
    try {
      // 先从L1内存缓存获取
      const l1Value = memoryCache.get(key);
      if (l1Value !== undefined) {
        logger.debug('L1缓存命中', { key });
        return l1Value;
      }

      // 如果Redis可用，从L2获取
      if (redisAvailable && redis) {
        const l2Value = await redis.get(key);
        if (l2Value !== null) {
          logger.debug('L2缓存命中', { key });
          const parsedValue = JSON.parse(l2Value);

          // 将数据写回L1缓存
          memoryCache.set(key, parsedValue, this.l1TTL);

          return parsedValue;
        }
      }

      logger.debug('缓存未命中', { key });
      return null;
    } catch (error) {
      logger.error('缓存读取错误', { key, error: error.message });
      return null;
    }
  }

  /**
   * 设置缓存数据（同时写入L1和L2）
   */
  async set(key, value, ttl = this.defaultTTL) {
    try {
      // 写入L1内存缓存
      memoryCache.set(key, value, Math.min(ttl, this.l1TTL));

      // 如果Redis可用，写入L2
      if (redisAvailable && redis) {
        await redis.setex(key, ttl, JSON.stringify(value));
        logger.debug('数据写入L2缓存', { key, ttl });
      }

      return true;
    } catch (error) {
      logger.error('缓存写入错误', { key, error: error.message });
      return false;
    }
  }

  /**
   * 删除缓存数据
   */
  async delete(key) {
    try {
      // 从L1删除
      memoryCache.delete(key);

      // 从L2删除
      if (redisAvailable && redis) {
        await redis.del(key);
      }

      logger.debug('缓存数据已删除', { key });
      return true;
    } catch (error) {
      logger.error('缓存删除错误', { key, error: error.message });
      return false;
    }
  }

  /**
   * 批量删除匹配模式的键
   */
  async deletePattern(pattern) {
    try {
      // 清理L1缓存
      memoryCache.clear();

      // 清理L2缓存
      if (redisAvailable && redis) {
        const keys = await redis.keys(`${redisConfig.keyPrefix}${pattern}`);
        if (keys.length > 0) {
          // 移除前缀后再删除
          const keysWithoutPrefix = keys.map(k => k.replace(redisConfig.keyPrefix, ''));
          await redis.del(...keysWithoutPrefix);
          logger.info('批量删除缓存', { pattern, count: keys.length });
        }
      }

      return true;
    } catch (error) {
      logger.error('批量删除缓存错误', { pattern, error: error.message });
      return false;
    }
  }

  /**
   * 缓存预热
   */
  async warmUp(dataLoader) {
    try {
      logger.info('开始缓存预热');

      // 预热常用数据
      const warmUpTasks = [];

      // 预热活跃订单列表
      warmUpTasks.push(
        dataLoader.loadActiveOrders().then(orders => {
          const key = this.generateKey('orders', 'active', 'list');
          return this.set(key, orders, 600); // 10分钟
        })
      );

      // 预热供应商列表
      warmUpTasks.push(
        dataLoader.loadProviders().then(providers => {
          const key = this.generateKey('providers', 'list');
          return this.set(key, providers, 3600); // 1小时
        })
      );

      // 预热最近的报价数据
      warmUpTasks.push(
        dataLoader.loadRecentQuotes().then(quotes => {
          const key = this.generateKey('quotes', 'recent');
          return this.set(key, quotes, 300); // 5分钟
        })
      );

      await Promise.all(warmUpTasks);

      logger.info('缓存预热完成');
      return true;
    } catch (error) {
      logger.error('缓存预热失败', { error: error.message });
      return false;
    }
  }

  /**
   * 获取缓存统计信息
   */
  async getStats() {
    const stats = {
      l1: {
        size: memoryCache.size(),
        maxSize: memoryCache.maxSize,
      },
      l2: {
        available: redisAvailable,
        info: null,
      },
    };

    if (redisAvailable && redis) {
      try {
        const info = await redis.info('memory');
        stats.l2.info = info;
      } catch (error) {
        logger.error('获取Redis信息失败', { error: error.message });
      }
    }

    return stats;
  }

  /**
   * 使用缓存装饰器包装函数
   */
  wrap(fn, keyGenerator, ttl = this.defaultTTL) {
    return async (...args) => {
      const key = typeof keyGenerator === 'function' ? keyGenerator(...args) : keyGenerator;

      // 尝试从缓存获取
      const cached = await this.get(key);
      if (cached !== null) {
        return cached;
      }

      // 执行原函数
      const result = await fn(...args);

      // 将结果写入缓存
      await this.set(key, result, ttl);

      return result;
    };
  }
}

// 创建缓存实例
const cache = new MultiLevelCache();

// 缓存键生成辅助函数
const cacheKeys = {
  // 订单相关
  ordersList: (status, page = 1, limit = 10) =>
    cache.generateKey('orders', status, `page:${page}`, `limit:${limit}`),
  orderDetail: orderId => cache.generateKey('orders', orderId),
  orderQuotes: orderId => cache.generateKey('orders', orderId, 'quotes'),

  // 供应商相关
  providersList: () => cache.generateKey('providers', 'list'),
  providerDetail: providerId => cache.generateKey('providers', providerId),
  providerOrders: (providerId, page = 1) =>
    cache.generateKey('providers', providerId, 'orders', `page:${page}`),

  // 报价相关
  lowestQuotes: orderIds => cache.generateKey('quotes', 'lowest', orderIds.join('-')),
  quotesByOrder: orderId => cache.generateKey('quotes', 'by-order', orderId),

  // 统计相关
  dailyStats: date => cache.generateKey('stats', 'daily', date),
  providerStats: providerId => cache.generateKey('stats', 'provider', providerId),
};

// 缓存失效策略
const cacheInvalidation = {
  // 订单创建后，清理相关缓存
  onOrderCreated: async () => {
    await cache.deletePattern('orders:active:*');
    await cache.deletePattern('stats:daily:*');
  },

  // 订单更新后，清理相关缓存
  onOrderUpdated: async orderId => {
    await cache.delete(cacheKeys.orderDetail(orderId));
    await cache.delete(cacheKeys.orderQuotes(orderId));
    await cache.deletePattern('orders:active:*');
    await cache.deletePattern('orders:closed:*');
  },

  // 报价创建后，清理相关缓存
  onQuoteCreated: async (orderId, providerId) => {
    await cache.delete(cacheKeys.orderQuotes(orderId));
    await cache.delete(cacheKeys.quotesByOrder(orderId));
    await cache.deletePattern(`quotes:lowest:*${orderId}*`);
    await cache.deletePattern(`providers:${providerId}:*`);
  },

  // 供应商更新后，清理相关缓存
  onProviderUpdated: async providerId => {
    await cache.delete(cacheKeys.providerDetail(providerId));
    await cache.delete(cacheKeys.providersList());
  },
};

// 导出
module.exports = {
  cache,
  cacheKeys,
  cacheInvalidation,
  redisAvailable: () => redisAvailable,
};

